package constructor;

public class Monster {
    String name;
    int level;
    int atk;

    // Constructor - 클래스명과 동일하게 작성
    Monster(String name, int level, int atk) {
        this.name = name;
        this.level = level;
        this.atk = atk;
    }

    // Constructor Overloadingg
    // this() 중복 제거
    Monster(String name, int level) {
        this(name, level, 0);
    }
}
